## 2. C / C++ stub – `pcapng_stubs.c`

> **Important** – The file must be compiled as C++ (`g++ … -c`) because it
> includes the C++ headers of *libpcapng*.  The public entry points are
> declared `extern "C"` so that OCaml can link to them.

```c
/* ----------------------------------------------------------------------
   pcapng_stubs.c  –  C++ stubs for the OCaml libpcapng bindings
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE      /* avoid name clashes with other libs */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>

#include <string>
#include <exception>
#include <stdexcept>
#include <cstring>
#include <cstdint>

extern "C" {
    /* The real libpcapng C++ API.  Replace this include with the actual
       header that ships with libpcapng.  For the purpose of this example we
       assume the following minimal interface. */
    #include "libpcapng.hpp"
}

/* ----------------------------------------------------------------------
   Helper macros for dealing with custom blocks
   ---------------------------------------------------------------------- */

#define Iterator_val(v)   (*((Pcapng::iterator **) Data_custom_val(v)))
#define Frame_val(v)      (*((Pcapng::Frame **) Data_custom_val(v)))

/* ----------------------------------------------------------------------
   Finalisers – called when the OCaml GC discards the custom block
   ---------------------------------------------------------------------- */

static void iterator_finalize(value v)
{
    Pcapng::iterator *it = Iterator_val(v);
    if (it != nullptr) {
        delete it;
    }
}

static void frame_finalize(value v)
{
    Pcapng::Frame *f = Frame_val(v);
    if (f != nullptr) {
        delete f;
    }
}

/* ----------------------------------------------------------------------
   Custom block descriptors
   ---------------------------------------------------------------------- */

static struct custom_operations iterator_ops = {
    "pcapng.iterator",
    iterator_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

static struct custom_operations frame_ops = {
    "pcapng.frame",
    frame_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_fixed_length_default
};

/* ----------------------------------------------------------------------
   Wrappers for allocating custom blocks
   ---------------------------------------------------------------------- */

static value alloc_iterator(Pcapng::iterator *it)
{
    value v = caml_alloc_custom(&iterator_ops, sizeof(Pcapng::iterator *), 0, 1);
    Iterator_val(v) = it;
    return v;
}

static value alloc_frame(Pcapng::Frame *f)
{
    value v = caml_alloc_custom(&frame_ops, sizeof(Pcapng::Frame *), 0, 1);
    Frame_val(v) = f;
    return v;
}

/* ----------------------------------------------------------------------
   OCaml entry points
   ---------------------------------------------------------------------- */

/* open_file : string -> iterator */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);

    std::string path = std::string(String_val(v_path));
    try {
        Pcapng pcap(path.c_str());               /* may throw */
        /* The iterator we expose is a *copy* of pcap.begin().  The copy
           owns its own state and can be moved independently of the Pcapng
           object.  The Pcapng object itself is destroyed immediately – the
           iterator keeps the underlying file handle alive (the library is
           written that way). */
        Pcapng::iterator *it = new Pcapng::iterator(pcap.begin());
        v_res = alloc_iterator(it);
    } catch (const std::exception &e) {
        caml_failwith(e.what());
    }

    CAMLreturn(v_res);
}

/* close : iterator -> unit */
extern "C" CAMLprim value caml_pcapng_close(value v_it)
{
    CAMLparam1(v_it);
    /* The finaliser already deletes the iterator.  We just null it out so
       that a second call is a harmless no‑op. */
    Pcapng::iterator *it = Iterator_val(v_it);
    if (it != nullptr) {
        delete it;
        Iterator_val(v_it) = nullptr;
    }
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Frame accessors – they receive a (already allocated) frame value and
   return a plain OCaml value.
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_pcapng_frame_data(value v_frame)
{
    CAMLparam1(v_frame);
    CAMLlocal1(v_bytes);

    Pcapng::Frame *f = Frame_val(v_frame);
    const std::vector<uint8_t> &payload = f->payload();

    v_bytes = caml_alloc_string(payload.size());
    memcpy(String_val(v_bytes), payload.data(), payload.size());

    CAMLreturn(v_bytes);
}

extern "C" CAMLprim value caml_pcapng_frame_timestamp(value v_frame)
{
    CAMLparam1(v_frame);
    Pcapng::Frame *f = Frame_val(v_frame);
    int64_t ts = f->timestamp();   /* nanoseconds since epoch */
    CAMLreturn(caml_copy_int64(ts));
}

extern "C" CAMLprim value caml_pcapng_frame_orig_len(value v_frame)
{
    CAMLparam1(v_frame);
    Pcapng::Frame *f = Frame_val(v_frame);
    CAMLreturn(Val_int(f->orig_len()));
}

/* ----------------------------------------------------------------------
   next : iterator -> frame option
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_pcapng_next(value v_it)
{
    CAMLparam1(v_it);
    CAMLlocal1(v_res);
    Pcapng::iterator *it = Iterator_val(v_it);

    if (it == nullptr) caml_failwith("iterator already closed");

    if (it->at_end()) {
        v_res = Val_int(0);          /* None */
    } else {
        /* Copy the current frame – the iterator stays valid after we
           advance it. */
        Pcapng::Frame *f = new Pcapng::Frame(*it->frame());
        v_res = caml_alloc(1, 0);    /* Some */
        Store_field(v_res, 0, alloc_frame(f));
        ++(*it);                     /* advance iterator */
    }

    CAMLreturn(v_res);
}

/* ----------------------------------------------------------------------
   iter : iterator -> (frame -> unit) -> unit
   ---------------------------------------------------------------------- */

extern "C" CAMLprim value caml_pcapng_iter(value v_it, value v_cb)
{
    CAMLparam2(v_it, v_cb);
    CAMLlocal1(v_frame);
    Pcapng::iterator *it = Iterator_val(v_it);

    if (it == nullptr) caml_failwith("iterator already closed");

    /* The loop is performed in C – we do not allocate a new OCaml stack
       frame for each iteration, which makes the function safe for huge
       captures. */
    while (!it->at_end()) {
        /* Build a temporary frame value that is *not* registered with the
           GC (because we free it manually after the callback). */
        Pcapng::Frame *f = new Pcapng::Frame(*it->frame());
        v_frame = alloc_frame(f);   /* registers a finaliser */
        /* Call the OCaml closure */
        caml_callback_exn(v_cb, v_frame);
        if (Is_exception_result(v_frame)) {
            /* Propagate the exception – the iterator stays alive so the
               user can decide to close it later. */
            caml_raise(v_frame);
        }
        /* The frame is now owned by the OCaml side; the next iteration
           will allocate a fresh one. */
        ++(*it);                     /* advance */
    }

    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   The stub file must expose the C symbols with the exact names that
   the OCaml compiler expects (caml_…); the .mli file declares the
   external functions.
   ---------------------------------------------------------------------- */
```

> **Explanation of the design decisions**

| Design point | Why it was chosen |
|--------------|-------------------|
| **Custom blocks (`alloc_custom`)** | Guarantees that the C++ objects are freed exactly when the OCaml value is GC‑collected; no manual `free` needed by the user. |
| **Separate `iterator` and `frame` types** | Keeps the public API simple and type‑safe; a frame can be passed around independently of the iterator. |
| **`iter` implemented in C** | Prevents building a huge OCaml call‑stack; the callback is invoked directly on each frame, and any exception bubbles out immediately. |
| **`next` returning an `option`** | Gives the user full control (early exit, selective processing) without needing to write a C‑level loop. |
| **Copy‑on‑read (`new Frame(*it->frame())`)** | Guarantees that the frame value lives at least as long as the user needs it, even after the iterator moves forward. |
| **Exception handling (`caml_callback_exn`)** | If the user‑supplied OCaml callback raises, iteration stops and the exception propagates, exactly as a normal OCaml higher‑order function would behave. |
| **`close` idempotent** | Mirrors the semantics of many OCaml libraries (e.g. `Unix.close`) and makes the API easier to use in `finally`‑style code. |

---

## 3. Minimal Makefile fragment (for reference)

```make
# ----------------------------------------------------------------------
# Makefile fragment – how to compile the stubs
# ----------------------------------------------------------------------
OCAMLFLAGS   = -thread -I +ocaml
CXXFLAGS     = -O2 -Wall -fPIC $(OCAMLFLAGS) -std=c++17
LIBS         = -lstdc++ -lpcapng   # <-- adjust to your libpcapng name

all: libpcapng_stubs.a pcapng.cma

libpcapng_stubs.a: pcapng_stubs.o
    ar rcs $@ $^

pcapng_stubs.o: pcapng_stubs.c
    $(CXX) $(CXXFLAGS) -c -o $@ $<

pcapng.cma: pcapng.cmi pcapng.cmo libpcapng_stubs.a
    ocamlc -a -o $@ $^ $(LIBS)

clean:
    rm -f *.o *.a *.cmi *.cmo *.cma
```

*Compile with*  

```sh
make
```

and then you can use the library in OCaml:

```ocaml
(* example.ml ---------------------------------------------------------- *)
let () =
  let it = Pcapng.open_file "sample.pcapng" in
  (* 1. using the callback style *)
  Pcapng.iter it (fun frm ->
      Printf.printf "frame %Ld bytes\n%!"
        (Int64.of_int (Bytes.length (Pcapng.data frm)));
    );
  (* 2. using manual pull *)
  let rec loop () =
    match Pcapng.next it with
    | None -> ()
    | Some frm ->
        Printf.printf "timestamp = %Ld\n%!"
          (Pcapng.timestamp frm);
        loop ()
  in
  loop ();
  Pcapng.close it
```

Compile the example with  

```sh
ocamlc -I . -o example pcapng.cma example.ml
```

---

## 4. Summary

* The **`.mli`** file gives a clean, high‑level OCaml API (`open_file`, `close`,
  `iter`, `next`, and frame accessors).  
* The **C++ stub** (`pcapng_stubs.c`) implements the glue using OCaml custom
  blocks, a finaliser for memory safety, and `caml_callback_exn` for invoking
  user‑provided OCaml functions.  
* The binding is **exception‑safe**, **GC‑friendly**, and works equally well for
  the “run a piece of user code for each frame” pattern (`iter`) and for the
  more manual “pull‑based” style (`next`).  

Feel free to adapt the stub to the exact signatures of the real *libpcapng*
C++ API (e.g. different frame field names). The overall structure – custom
blocks, finalisers, and a C‑side iteration loop – will stay the same.
